import ldap3
from ldap3.utils.conv import escape_filter_chars


def search_user_by_username(ldap_server_url: str, base_dn: str, username: str,
                            bind_dn: str = None, bind_password: str = None,
                            search_attributes: list = None) -> list:
    """
    Search for users in an LDAP directory by their username.
    
    Sanitizes the username input to prevent LDAP injection attacks.
    
    Args:
        ldap_server_url: The LDAP server URL (e.g., 'ldap://localhost:389')
        base_dn: The base DN to search from (e.g., 'dc=example,dc=com')
        username: The username to search for (will be sanitized)
        bind_dn: Optional DN to bind with for authentication
        bind_password: Optional password for bind DN
        search_attributes: Optional list of attributes to retrieve.
                          Defaults to common user attributes.
    
    Returns:
        A list of dictionaries containing the matched user entries.
    
    Raises:
        ldap3.core.exceptions.LDAPException: If there's an LDAP communication error.
        ValueError: If required parameters are missing or invalid.
    """
    if not ldap_server_url:
        raise ValueError("LDAP server URL is required")
    if not base_dn:
        raise ValueError("Base DN is required")
    if not username:
        raise ValueError("Username is required")

    if search_attributes is None:
        search_attributes = ['cn', 'uid', 'mail', 'displayName', 'sn', 'givenName']

    # Sanitize the username to prevent LDAP injection
    # escape_filter_chars escapes special characters: *, (, ), \, NUL, /, and others
    sanitized_username = escape_filter_chars(username)

    # Build the search filter with the sanitized username
    search_filter = '(&(objectClass=person)(|(uid={0})(cn={0})(sAMAccountName={0})))'.format(
        sanitized_username
    )

    # Create the LDAP server and connection
    server = ldap3.Server(ldap_server_url, get_info=ldap3.ALL)

    if bind_dn and bind_password:
        connection = ldap3.Connection(
            server,
            user=bind_dn,
            password=bind_password,
            auto_bind=True,
            read_only=True
        )
    else:
        # Anonymous bind
        connection = ldap3.Connection(
            server,
            auto_bind=True,
            read_only=True
        )

    try:
        # Perform the search
        connection.search(
            search_base=base_dn,
            search_filter=search_filter,
            search_scope=ldap3.SUBTREE,
            attributes=search_attributes,
            size_limit=100  # Limit results to prevent abuse
        )

        # Process and return results
        results = []
        for entry in connection.entries:
            user_dict = {
                'dn': entry.entry_dn,
            }
            for attribute in search_attributes:
                if hasattr(entry, attribute) and getattr(entry, attribute).value is not None:
                    value = getattr(entry, attribute).value
                    # If it's a list with one element, unwrap it
                    if isinstance(value, list) and len(value) == 1:
                        value = value[0]
                    user_dict[attribute] = value
            results.append(user_dict)

        return results

    finally:
        connection.unbind()


